            ) && has_local_database_marker(value)
        });

    if !has_local_database_marker(database_name) && !query_has_schema_marker {
        anyhow::bail!("{DATABASE_URL_ENV} must visibly target a Scope local/dev database");
    }

    Ok(())
}

